const AuraCoach=(function(){const e={'mathematics':{title:'Mathematics Study Strategies',tips:['Break down problems: Work through 3 core proofs or mathematical concepts, then take a physical break.','Anti-Burnout tip: Avoid math after 9 PM. Visual-spatial reasoning drops sharply with sleep deprivation.','Active recall: Write down formulas from memory on a blank sheet before doing practice exercises.','Recommended rhythm: 35 minutes study (deep problem-solving) + 7 minutes physical break (hydrate).'],motto:'Solve with structure. Rest to consolidate numerical patterns.'},'computer-science':{title:'Computer Science & Coding Strategies',tips:['Coding focus: Code in blocks of 40 minutes, followed by an immediate screen-free break to avoid eye strain.','Rubber duck debugging: Explaining code logic to an imaginary partner reduces mental frustration and cortisol.','Anti-Burnout tip: Stand up, stretch, and focus your eyes on an object 20 feet away during your breaks.','Code-Break Balance: Avoid continuous typing for more than 1 hour. Carpal and cognitive fatigue build together.'],motto:'Compile your knowledge in modules. Execute breaks without errors.'},'physics':{title:'Physics & Chemistry Formulas & Application',tips:['Concept Mapping: Visualize formulas as physical systems (e.g. gravity, energy transfer, chemical bonding).','Anti-Burnout tip: Alternate between formula memorization and practice calculations to keep different cognitive zones active.','Break Activity: Do 10 jumping jacks or a deep stretch to circulate oxygen to your brain.','Rhythm: 30m deep reading + 5m physical stretching.'],motto:'Energy is conserved. Manage your mental energy just like thermodynamics.'},'literature':{title:'Literature, Humanities & Languages',tips:['Semantic overload: Reading text for hours causes semantic fatigue. Switch to summary note writing every 25 minutes.','Vocal reading: Read difficult paragraphs aloud to stimulate auditory memory and prevent zone-outs.','Anti-Burnout tip: Close your eyes for 3 minutes between chapters. Let your visual cortex relax.','Rhythm: 25m active text reading + 5m soft mental review.'],motto:'Translate information into wisdom. Rest between paragraphs.'},'general':{title:'General Exam Conditioning',tips:['Spaced Repetition: Review high-yield summary cards for 20 minutes, then rest for 5 minutes.','Anti-Burnout tip: Protect your sleep. Studying while tired has a 60% lower consolidation rate.','Hydration check: Dehydration reduces concentration by 15%. Drink a glass of water every break.','Rhythm: Standard 25-minute Pomodoro is optimal for continuous study endurance.'],motto:'Consistency beats cramming. Protect your mental stamina.'}};const t={'exam-stress':{reply:"Exam stress is a natural sympathetic response, but if left uncontrolled, it spikes your Burnout Index and impairs active recall. Here is a **3-step stress regulation routine**:\n\n1. **Box Breathing**: Inhale for 4 seconds, hold for 4 seconds, exhale for 4 seconds, hold for 4 seconds. Let's do it together using the 'guided breathing exercise' option!\n2. **Break down the syllabus**: Write down only the next *single task* you need to do, ignoring the rest of the syllabus for the next hour.\n3. **Subject Check**: Ensure you select your current study subject at the top header to align your study rhythms perfectly.",action:null},'burnout-prevention':{reply:"To prevent burnout, we need to balance **Cognitive Load** with **Parasympathetic Reset**. Here are my key rules based on cognitive science:\n\n1. **The 50-10 Rule**: Never study continuously for more than 50 minutes without a 10-minute pure screen-free break.\n2. **Tech-Free Breaks**: Looking at your phone during a study break is NOT a break! Your brain still processes pixels, blocking memory consolidation. Walk around or drink water.\n3. **Early Warning Indicator**: Keep an eye on your **Burnout Index** gauge on the dashboard. If it climbs past 50, it is an automatic signal that your focus efficiency has dropped and breaks are mandatory.",action:null},'subject-routine':{reply:"I will generate a customized routine based on your selected subject. Please ensure your active subject is correct in the top header. Here is your optimal plan:",action:'subject-routine-custom'},'take-break':{reply:"Let's take a quick guided breathing break to lower your cortisol levels and clear your mental workspace. I've activated the visual breathing bubble below. Focus on the bubble and synchronize your breathing:",action:'start-breathing'}};function n(t,n,o){const s=e[o]||e.general;if(n>=75){return`⚠️ **CRITICAL BURNOUT WARNING (${n}/100)**: Your cognitive load is saturated and mental fatigue is severe. Stop studying immediately! Aura recommends a 15-minute Long Break and a guided breathing session to prevent exam-cram failure.`}if(n>=50){return`⚠️ **Elevated Burnout (${n}/100)**: Fatigue is building up. Your focus efficiency is dropping. Tip: ${s.tips[1]||'Take a pure tech-free screen break.'} Finish your current Pomodoro round and take a mandatory 10-minute break.`}if(t<40){return`🎯 **Low Focus Detected (${t}/100)**: Distractions or tab blurring have interrupted your rhythm. Let's restart your attention span. Subject strategy tip: *"${s.tips[2]}"* Let's start a new Study Session right now.`}if(t>=80&&n<30){return`🚀 **Superb Performance!** Focus: **${t}**, Burnout: **${n}**. You are in a flow state studying **${s.title}**. Action tip: *"${s.tips[0]}"* Keep going!`}return`✨ Aura Coach: You are doing great studying **${s.title}**. Remember: *"${s.motto}"* Take your breaks on time to maximize long-term memory retrieval!`}function o(n,o){const s=n.trim().toLowerCase();if(t[n]){const c=t[n];if(c.action==='subject-routine-custom'){const a=e[o.subject]||e.general;const r=`${c.reply} **${a.title}**:\n\n* **Ideal Rhythm**: ${a.tips[3]||'25m study + 5m break'}\n* **Active recall technique**: ${a.tips[2]}\n* **Anti-Burnout Rule**: ${a.tips[1]}\n\nLet's apply these guidelines! Reset your timer and start studying.`;return{reply:r,action:null}}return c}if(s.includes('stress')||s.includes('anxious')||s.includes('pressure')||s.includes('panic')){return t['exam-stress']}if(s.includes('burnout')||s.includes('tired')||s.includes('fatigue')||s.includes('exhaust')||s.includes('headache')){return t['burnout-prevention']}if(s.includes('break')||s.includes('breath')||s.includes('meditate')||s.includes('relax')){return t['take-break']}if(s.includes('routine')||s.includes('schedule')||s.includes('subject')||s.includes('plan')){const a=e[o.subject]||e.general;const r=`Generating customized focus routine for your selected subject **${a.title}**:\n\n* **Ideal Rhythm**: ${a.tips[3]||'25m study + 5m break'}\n* **Active Recall strategy**: ${a.tips[2]}\n* **Daily Consolidator rule**: ${a.tips[1]}\n* **Motto**: *"${a.motto}"*`;return{reply:r,action:null}}if(s.includes('analyze')||s.includes('performance')||s.includes('report')||s.includes('how am i')){return{reply:s(o),action:null}}let c=`I've analyzed your current focus logs. You have studied for **${o.productiveTime} minutes** today with **${o.blurCount} tab-blur distractions**.\n\n`;if(o.burnoutScore>=50){c+=`Looking at your **Burnout Index (${o.burnoutScore}/100)**, you are showing high mental exhaust patterns. I suggest asking me about **"burnout prevention"** or taking a **guided breathing break**.`}else if(o.focusScore<50){c+=`Your **Focus Score (${o.focusScore}/100)** is on the lower side due to distractions. Try selecting **"subject-routine"** to see how to restructure your attention workspace.`}else{c+=`Your metrics are in excellent balance! Focus: **${o.focusScore}**, Burnout: **${o.burnoutScore}**. Keep up this consistency. Is there a specific subject strategy or stress control tips you would like to ask me about?`}return{reply:c,action:null}}function s(e){let t="";let n="";if(e.focusScore>=80){t="🏆 **Outstanding Flow State Performance**";n="Your cognitive attention channels are synchronized perfectly. You minimized browser distractions and completed your Pomodoro study cycles flawlessly."}else if(e.focusScore>=50){t="📈 **Healthy Productive Focus**";n="Good overall consistency. You completed study cycles, though minor tab blurs interrupted your flow. Try putting your phone in another room to elevate your concentration further."}else{t="⚠️ **Distraction-Heavy Performance**";n="Your attention span was highly fragmented today due to tab-blur events or self-reported distraction activities. Focus on starting single 25-minute Pomodoro sessions without opening other apps."}let o="";if(e.burnoutScore>=60){o="⚠️ **HIGH COGNITIVE FATIGUE INDEX**: Your brain is operating under severe stress or late-night fatigue. Continuous focus is causing micro-errors. You *must* sleep, take screen breaks, or do guided meditation."}else if(e.burnoutScore>=35){o="⚖️ **Moderate Mental Fatigue**: Your fatigue levels are elevated but manageable. Ensure you respect break timers and do not push past study rounds continuously."}else{o="✅ **Optimal Balance State**: Exceptional fatigue management. You took timely rest rounds, allowing your hippocampus to rest and consolidate long-term memory perfectly."}return`### **AURA COGNITIVE ASSESSMENT REPORT**\n\n**Focus Rating:** ${t}\n\n**Attention Metrics Summary:**\n* **Focus Score:** ${e.focusScore}/100\n* **Burnout Index:** ${e.burnoutScore}/100\n* **Study Time:** ${e.productiveTime} minutes\n* **Screen Distractions:** ${e.distractedTime} minutes\n* **Tab Blurs:** ${e.blurCount} incidents\n* **Completed Pomodoros:** ${e.pomoRounds} rounds\n\n**Fatigue Analysis:**\n${o}\n\n**Strategic Recommendation:**\n${n}\n\n*Aura Cognitive health system, calibrated for academic longevity.*`}return{getLiveSuggestion:n,processUserMessage:o,generatePerformanceAnalysis:s,subjectStrategies:e}})();
